/*!50003 DROP PROCEDURE IF EXISTS `get_admin_system_report` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `get_admin_system_report`()
BEGIN
    -- Result Set 1: Overall System Stats
    SELECT 
        (SELECT COUNT(*) FROM users) as total_users,
        (SELECT COUNT(*) FROM users WHERE user_type = 'investor') as total_investors,
        (SELECT COUNT(*) FROM users WHERE user_type = 'developer') as total_developers,
        (SELECT COUNT(*) FROM users WHERE kyc_verified = 0) as kyc_pending,
        (SELECT COUNT(*) FROM properties) as total_properties,
        (SELECT COALESCE(SUM(total_shares_issued), 0) FROM properties) as total_shares_issued,
        (SELECT COALESCE(SUM(total_revenue), 0) FROM dividend_distributions) as total_revenue,
        (SELECT COALESCE(SUM(total_expenses), 0) FROM dividend_distributions) as total_expenses,
        (SELECT COALESCE(SUM(net_income), 0) FROM dividend_distributions) as net_income,
        (SELECT COUNT(*) FROM lease_agreements 
         WHERE CURDATE() BETWEEN lease_start_date AND lease_end_date) as active_leases;

    -- Result Set 2: Property Chart Data
    SELECT 
        p.property_name as name,
        COALESCE(d.total_revenue, 0) as revenue, 
        COALESCE(d.total_expenses, 0) as expenses, 
        COALESCE(d.net_income, 0) as net
    FROM properties p
    LEFT JOIN dividend_distributions d ON p.property_id = d.property_id;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `get_developer_profile` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `get_developer_profile`(IN p_developer_id INT)
BEGIN
    -- Result set 1: Developer profile card
    SELECT
        d.developer_id,
        d.user_id,
        u.full_name              AS name,
        u.email,
        d.company_name,
        d.total_properties_listed,
        d.verified
    FROM   Developers d
    JOIN   Users u ON d.user_id = u.user_id
    WHERE  d.developer_id = p_developer_id;

    -- Result set 2: Full property detail rows
    SELECT
        p.property_id,
        p.property_name,
        p.property_type,
        p.city,
        p.state,
        p.total_area_sqft,
        p.total_shares_issued,
        p.available_shares,
        p.current_share_price,
        dd.distribution_id,
        dd.total_revenue,
        dd.total_expenses,
        dd.net_income,
        dd.dividend_per_share,
        t.tenant_id,
        t.tenant_name,
        t.business_type,
        t.contact_email         AS tenant_email,
        la.lease_id,
        la.lease_start_date,
        la.lease_end_date,
        la.yearly_rent
    FROM   Properties p
    LEFT JOIN Dividend_Distributions dd ON p.property_id = dd.property_id
    LEFT JOIN Lease_Agreements la       ON p.property_id = la.property_id
    LEFT JOIN Tenants t                 ON la.tenant_id   = t.tenant_id
    WHERE  p.developer_id = p_developer_id
    ORDER BY p.property_id;
END ;;
DELIMITER ;
