CREATE DEFINER=`root`@`localhost` PROCEDURE `get_developer_revenue_history`(IN p_user_id INT)
BEGIN
    DECLARE v_dev_id INT;
    SELECT developer_id INTO v_dev_id FROM developers WHERE user_id = p_user_id;

    SELECT 
        COALESCE(rr.revenue_id, 0) as revenue_id, 
        p.property_name, 
        COALESCE(rr.revenue_month, 'N/A') as revenue_month, 
        COALESCE(rr.amount_collected, 0) as amount_collected, 
        COALESCE(rr.payment_status, 'pending') as payment_status
    FROM properties p
    LEFT JOIN revenue_records rr ON p.property_id = rr.property_id
    WHERE p.developer_id = v_dev_id;
END ;;
DELIMITER ;
