/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `get_investor_financial_history`(IN p_user_id INT)
BEGIN
    DECLARE v_investor_id INT;
    SELECT investor_id INTO v_investor_id FROM investors WHERE user_id = p_user_id;

    -- Result Set 1: Share Transactions (Safety: ID check)
    SELECT 
        COALESCE(t.transaction_id, 0) as transaction_id, 
        COALESCE(p.property_name, 'No Transactions') as property_name, 
        COALESCE(t.transaction_type, 'N/A') as transaction_type, 
        COALESCE(t.shares_quantity, 0) as shares_quantity, 
        COALESCE(t.price_per_share, 0) as price_per_share,
        COALESCE(t.total_amount, 0) as total_amount
    FROM (SELECT v_investor_id as inv_id) dummy
    LEFT JOIN share_transactions t ON t.buyer_id = dummy.inv_id OR t.seller_id = dummy.inv_id
    LEFT JOIN properties p ON t.property_id = p.property_id;

    -- Result Set 2: Dividend Payments (Safety: COALESCE)
    SELECT 
        COALESCE(dp.payment_id, 0) as payment_id, 
        COALESCE(p.property_name, 'N/A') as property_name, 
        COALESCE(dp.shares_held, 0) as shares_held, 
        COALESCE(dp.dividend_amount, 0) as dividend_amount, 
        COALESCE(dp.payment_status, 'pending') as payment_status
    FROM (SELECT v_investor_id as inv_id) dummy
    LEFT JOIN dividend_payments dp ON dp.investor_id = dummy.inv_id
    LEFT JOIN dividend_distributions dd ON dp.distribution_id = dd.distribution_id
    LEFT JOIN properties p ON dd.property_id = p.property_id;
END ;;
DELIMITER ;
