CREATE DEFINER=`root`@`localhost` PROCEDURE `get_investor_profile`(IN p_investor_id INT)
BEGIN
    -- Result set 1: Profile card
    SELECT
        i.investor_id,
        u.full_name              AS name,
        u.email,
        i.wallet_balance         AS balance,
        i.total_invested,
        i.total_dividends_earned,
        i.risk_profile,
        u.kyc_verified
    FROM   Investors i
    JOIN   Users u ON i.user_id = u.user_id
    WHERE  i.investor_id = p_investor_id;

    -- Result set 2: Holdings for bubbles + pie chart
    SELECT
        so.ownership_id,
        so.property_id,
        p.property_name,
        p.property_type,
        p.city,
        so.shares_owned,
        so.total_invested                        AS invested_in_property,
        so.average_purchase_price,
        p.current_share_price,
        so.shares_owned * p.current_share_price  AS current_value
    FROM   Share_Ownership so
    JOIN   Properties p ON so.property_id = p.property_id
    WHERE  so.investor_id = p_investor_id AND so.shares_owned > 0
    ORDER BY so.total_invested DESC;
END ;;
DELIMITER ;
