DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `process_dividend_payout`()
BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE cur_dist_id INT;
    DECLARE cur_prop_id INT;
    DECLARE cur_div_per_share DECIMAL(15,2);
    
    -- Cursor to iterate through properties with defined distributions
    DECLARE dist_cursor CURSOR FOR 
        SELECT distribution_id, property_id, COALESCE(dividend_per_share, 0) 
        FROM dividend_distributions;
        
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    OPEN dist_cursor;

    read_loop: LOOP
        FETCH dist_cursor INTO cur_dist_id, cur_prop_id, cur_div_per_share;
        IF done THEN
            LEAVE read_loop;
        END IF;

        -- 1. Insert records into dividend_payments
        -- Ensuring dividend_amount is calculated as a number, never NULL
        INSERT INTO dividend_payments (distribution_id, investor_id, shares_held, dividend_amount, payment_status)
        SELECT 
            cur_dist_id, 
            s.investor_id, 
            s.shares_owned, 
            COALESCE(s.shares_owned * cur_div_per_share, 0), 
            'completed'
        FROM share_ownership s
        WHERE s.property_id = cur_prop_id;

        -- 2. Update investor wallets
        -- Using COALESCE on current balance to handle new accounts with NULL balances
        UPDATE investors i
        JOIN share_ownership s ON i.investor_id = s.investor_id
        SET 
            i.wallet_balance = COALESCE(i.wallet_balance, 0) + COALESCE(s.shares_owned * cur_div_per_share, 0),
            i.total_dividends_earned = COALESCE(i.total_dividends_earned, 0) + COALESCE(s.shares_owned * cur_div_per_share, 0)
        WHERE s.property_id = cur_prop_id;

    END LOOP;

    CLOSE dist_cursor;
END ;;
DELIMITER ;
