/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `purchase_shares`(
    IN  p_investor_id  INT,
    IN  p_property_id  INT,
    IN  p_quantity     INT,
    OUT p_result       VARCHAR(200)
)
BEGIN
    DECLARE v_wallet       DECIMAL(14,2);
    DECLARE v_share_price  DECIMAL(12,2);
    DECLARE v_available    INT;
    DECLARE v_total_cost   DECIMAL(14,2);

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        SET p_result = 'ERROR: Transaction failed and rolled back.';
    END;

    START TRANSACTION;

    SELECT wallet_balance
    INTO   v_wallet
    FROM   Investors
    WHERE  investor_id = p_investor_id
    FOR UPDATE;

    SELECT current_share_price, available_shares
    INTO   v_share_price, v_available
    FROM   Properties
    WHERE  property_id = p_property_id
    FOR UPDATE;

    SET v_total_cost = p_quantity * v_share_price;

    IF p_quantity <= 0 THEN
        ROLLBACK;
        SET p_result = 'ERROR: Quantity must be greater than zero.';

    ELSEIF v_available < p_quantity THEN
        ROLLBACK;
        SET p_result = 'ERROR: Not enough shares available.';

    ELSEIF v_wallet < v_total_cost THEN
        ROLLBACK;
        SET p_result = 'ERROR: Insufficient wallet balance.';

    ELSE
        UPDATE Investors
        SET    wallet_balance = wallet_balance - v_total_cost,
               total_invested = total_invested + v_total_cost
        WHERE  investor_id = p_investor_id;

        UPDATE Properties
        SET    available_shares = available_shares - p_quantity
        WHERE  property_id = p_property_id;

        INSERT INTO Share_Transactions
            (property_id, buyer_id, seller_id, transaction_type,
             shares_quantity, price_per_share, total_amount, transaction_date)
        VALUES
            (p_property_id, p_investor_id, NULL, 'buy',
             p_quantity, v_share_price, v_total_cost, CURDATE());

        INSERT INTO Share_Ownership
            (investor_id, property_id, shares_owned,
             total_invested, average_purchase_price)
        VALUES
            (p_investor_id, p_property_id, p_quantity,
             v_total_cost, v_share_price)
        ON DUPLICATE KEY UPDATE
            total_invested         = total_invested + v_total_cost,
            average_purchase_price = (total_invested + v_total_cost)
                                     / (shares_owned + p_quantity),
            shares_owned           = shares_owned + p_quantity;

        COMMIT;
        SET p_result = CONCAT('SUCCESS: Bought ', p_quantity,
                              ' shares of property ', p_property_id,
                              ' for Rs.', v_total_cost);
    END IF;
END ;;
DELIMITER ;
